INSERT INTO "plants" VALUES('ShengShiHua','生石花','多肉植物','较高','{"name":"生石花","standard_name":"生石花","latinName":"Lithops","synonyms":["石头花","屁股花"],"family":"番杏科生石花属","origin":"非洲南部"}','{"category":"多肉植物","growthHabit":"多年生小型多肉","flowerColor":"黄色或白色","floweringSeason":"秋季至初冬","fragrance":"无","landscapeUse":"奇特盆栽、岩石园组合","potSuitable":true,"symbolism":"顽强、伪装"}','{"careDifficulty":"较高","lightRequirement":"喜全日照，光照不足会变畸长","waterRequirement":"极耐旱，生长期外需严格断水","temperature":"15-30℃","humidity":"保持干燥通风","soilRequirement":"纯颗粒或极高比例颗粒土","droughtTolerance":"极强","shadeTolerance":"差","coldTolerance":"极差，越冬需10℃以上","watering":"蜕皮期间绝对禁止浇水，正常期每月一次","fertilizing":"基本不需要，换盆时可加一点底肥","pruning":"蜕皮后的老皮会自行干枯，不可强行剥除","propagation":"播种、分头","pests":"鸟类啄食、根结线虫","safetyInfo":"无毒","specialNotes":"蜕皮期是关键，水多必烂，需极高通风"}','2026-01-24 09:04:56',NULL);
INSERT INTO "plants" VALUES('GuiBeiZhu','龟背竹','室内观叶植物','容易','{"name":"龟背竹","standard_name":"龟背竹","latinName":"Monstera deliciosa","synonyms":["蓬莱蕉","龟背蕉"],"family":"天南星科龟背竹属","origin":"墨西哥热带雨林"}','{"category":"室内观叶植物","growthHabit":"多年生常绿攀援灌木","flowerColor":"淡黄色（室内难开花）","floweringSeason":"秋季","fragrance":"清香（花期）","landscapeUse":"大型盆栽、网红家居背景、北欧风装饰","potSuitable":true,"symbolism":"健康长寿、招财进宝"}','{"careDifficulty":"容易","lightRequirement":"喜散射光，耐半阴，忌强光直射","waterRequirement":"喜湿润，不耐积水","temperature":"20-30℃","humidity":"高湿度（＞60%）","soilRequirement":"肥沃、疏松、排水良好的微酸性壤土","droughtTolerance":"一般","shadeTolerance":"极强","coldTolerance":"弱，低于10℃停止生长","watering":"生长旺季保持湿润，夏季多向叶片和气生根喷水","fertilizing":"生长季每2周施一次有机肥或液态肥","pruning":"剪除发黄老叶，过长气生根可引回土中","propagation":"扦插、分株","pests":"介壳虫、红蜘蛛","safetyInfo":"汁液有刺激性，严禁误食","specialNotes":"气生根发达，具有极强的空气净化能力"}','2026-01-24 09:04:56',NULL);
INSERT INTO "plants" VALUES('JinBianHuWeiLan','金边虎尾兰','室内观叶植物','极易','{"name":"金边虎尾兰","standard_name":"金边虎尾兰","latinName":"Sansevieria trifasciata ''Laurentii''","synonyms":["虎皮兰","千岁兰"],"family":"天门冬科虎尾兰属","origin":"非洲西部热带地区"}','{"category":"室内观叶植物","growthHabit":"常绿多年生草本","flowerColor":"白绿色","floweringSeason":"极少开花","fragrance":"淡雅","landscapeUse":"除甲醛标兵、卧室盆栽、写字楼点缀","potSuitable":true,"symbolism":"坚韧、长寿"}','{"careDifficulty":"极易","lightRequirement":"适应性广，从全光照到半阴环境均可","waterRequirement":"耐旱，忌积水","temperature":"18-27℃","humidity":"适应环境湿度","soilRequirement":"排水良好的砂质壤土","droughtTolerance":"极强","shadeTolerance":"极强","coldTolerance":"一般，冬季不宜低于5℃","watering":"干透浇透，宁干勿湿，冬季一个月一次","fertilizing":"每半年施用少量通用型颗粒肥即可","pruning":"剪掉叶尖受损部分或衰老叶片","propagation":"分株（能保持金边）、扦插（会丢失金边）","pests":"极少，过湿易腐烂","safetyInfo":"微毒，误食可致恶心呕吐","specialNotes":"著名的''植物呼吸机''，夜间也能释放氧气"}','2026-01-24 09:04:56',NULL);
INSERT INTO "plants" VALUES('ShuangXianZhuYu','双线竹芋','室内观叶植物','较高','{"name":"双线竹芋","standard_name":"双线竹芋","latinName":"Calathea ornata","synonyms":["红双线竹芋"],"family":"竹芋科肖竹芋属","origin":"南美洲热带地区"}','{"category":"室内观叶植物","growthHabit":"多年生常绿草本","flowerColor":"白色（罕见）","floweringSeason":"夏季","fragrance":"无","landscapeUse":"中小型精巧盆栽、桌面装饰","potSuitable":true,"symbolism":"梦想成真、诱惑"}','{"careDifficulty":"较高","lightRequirement":"喜半阴，忌阳光直射，光太强叶片会焦枯","waterRequirement":"喜偏湿，忌盆土积水","temperature":"18-25℃","humidity":"极高湿度（＞70%），叶尖易干","soilRequirement":"疏松、肥沃、排水好的微酸性土","droughtTolerance":"弱","shadeTolerance":"强","coldTolerance":"极弱，低于15℃需保温","watering":"生长旺季保持土表湿润，禁止用含有漂白粉的自来水直冲","fertilizing":"生长季每月一次稀薄氮钾肥","pruning":"剪掉发黑的叶尖和底部老叶","propagation":"分株","pests":"红蜘蛛、叶斑病","safetyInfo":"无毒","specialNotes":"叶面有如手绘般的粉红色条纹，夜晚叶片会合拢向上"}','2026-01-24 09:04:56',NULL);
INSERT INTO "plants" VALUES('KuLaSuoLuHui','库拉索芦荟','中药材/蔬果类','容易','{"name":"库拉索芦荟","standard_name":"翠叶芦荟","latinName":"Aloe vera","synonyms":["真芦荟","巴巴多斯芦荟"],"family":"阿福花科芦荟属","origin":"非洲、地中海地区"}','{"category":"中药材/蔬果类","growthHabit":"多年生常绿肉质草本","flowerColor":"橙黄色","floweringSeason":"春季","fragrance":"无","landscapeUse":"家庭药用、美容、食用种植","potSuitable":true,"symbolism":"自尊自信、顽强的一生"}','{"careDifficulty":"容易","lightRequirement":"喜充足日照，不耐阴","waterRequirement":"极耐旱，怕积水","temperature":"20-30℃","humidity":"喜通风干燥","soilRequirement":"疏松透气排水好的沙壤土","droughtTolerance":"极强","shadeTolerance":"差","coldTolerance":"差，低于10℃易冻伤","watering":"宁干勿湿，干透后再等几天浇水","fertilizing":"春秋季施薄肥，夏季和休眠期不施肥","pruning":"收割底层肥厚老叶用于生活用途","propagation":"分株（吸芽）","pests":"炭疽病、介壳虫","safetyInfo":"可药用，但孕妇及部分体质需遵医嘱或皮操","specialNotes":"最著名的家种药用植物，叶肉可消炎美容"}','2026-01-24 09:04:57',NULL);
INSERT INTO "plants" VALUES('OuBoHe','欧薄荷','中药材/蔬果类','容易（侵略性强）','{"name":"欧薄荷","standard_name":"辣薄荷","latinName":"Mentha × piperita","synonyms":["胡椒薄荷","佩博薄荷"],"family":"唇形科薄荷属","origin":"欧洲"}','{"category":"中药材/蔬果类","growthHabit":"多年生宿根草本","flowerColor":"紫色小花","floweringSeason":"夏季","fragrance":"极浓郁中草药味、提神醒脑","landscapeUse":"香草花园、厨房阳台盆栽、地被覆盖","potSuitable":true,"symbolism":"美德、重逢"}','{"careDifficulty":"容易（侵略性强）","lightRequirement":"喜充足散射光，忌烈日暴晒","waterRequirement":"喜湿润，但不能泡水","temperature":"20-30℃","humidity":"中等湿度","soilRequirement":"疏松肥沃的有机土","droughtTolerance":"一般，干旱会萎蔫","shadeTolerance":"中等","coldTolerance":"极强，地下茎可耐零下低温","watering":"保持盆土湿润，表土微干即浇水","fertilizing":"生长期每半月施一次有机肥或液态肥","pruning":"定期修剪顶端（摘心）促进分枝，防徒长","propagation":"分株、扦插（遇水即活）","pests":"蚜虫、红蜘蛛","safetyInfo":"可食用，可降暑除异味","specialNotes":"根系蔓延极快，建议单独盆栽以免抢夺其他植物养分"}','2026-01-24 09:04:57',NULL);
INSERT INTO "plants" VALUES('MiDieXiang','迷迭香','中药材/蔬果类','中等','{"name":"迷迭香","standard_name":"迷迭香","latinName":"Salvia rosmarinus","synonyms":["海洋之露"],"family":"唇形科鼠尾草属","origin":"地中海沿岸"}','{"category":"中药材/蔬果类","growthHabit":"常绿小灌木","flowerColor":"浅蓝色或紫色","floweringSeason":"冬春季","fragrance":"醇厚松木清香、杀菌除味","landscapeUse":"西餐配菜、室内空气净化、绿篱","potSuitable":true,"symbolism":"回忆、忠贞不渝"}','{"careDifficulty":"中等","lightRequirement":"喜全日照，光照不足会瘦弱","waterRequirement":"耐旱，极怕积水积湿","temperature":"15-25℃","humidity":"低湿度，喜干燥通风环境","soilRequirement":"排水极好的沙质土或石灰质土","droughtTolerance":"强","shadeTolerance":"差","coldTolerance":"较强，部分品种可耐-5℃","watering":"宁干勿湿，严控晚间浇水","fertilizing":"每年春季施一次长效缓释肥即可","pruning":"剪下嫩枝用于料理，或修剪成特定球形","propagation":"顶芽扦插","pests":"根腐病、粉虱","safetyInfo":"著名的食用香料","specialNotes":"忌频繁移栽，小苗期需勤摘心"}','2026-01-24 09:04:57',NULL);
INSERT INTO "plants" VALUES('LuNaLian','露娜莲','多肉植物','容易','{"name":"露娜莲","standard_name":"露娜莲","latinName":"Echeveria ''Lola''","synonyms":["萝拉"],"family":"景天科拟石莲花属","origin":"墨西哥（园艺培育种）"}','{"category":"多肉植物","growthHabit":"多年生肉质草本","flowerColor":"橘红色或粉色","floweringSeason":"春季","fragrance":"无","landscapeUse":"组合盆栽、室内桌面装饰","potSuitable":true,"symbolism":"纯洁、宁静"}','{"careDifficulty":"容易","lightRequirement":"喜全日照，光照充足时叶尖呈淡紫色","waterRequirement":"耐旱，忌积水","temperature":"15-25℃","humidity":"保持干燥","soilRequirement":"颗粒比例较高的多肉专用土","droughtTolerance":"极强","shadeTolerance":"耐半阴，但易徒长","coldTolerance":"弱，低于5℃需移入室内","watering":"干透浇透，夏季严格控水","fertilizing":"生长季每月施一次颗粒缓释肥","pruning":"剪除底层枯叶，剪掉花箭可节省母株养分","propagation":"叶插、分株","pests":"煤烟病、蚧壳虫","safetyInfo":"无毒","specialNotes":"叶面覆有厚白粉，不可用手触摸或喷水在叶片上"}','2026-01-24 09:11:20',NULL);
INSERT INTO "plants" VALUES('XiongTongZi','熊童子','多肉植物','较高','{"name":"熊童子","standard_name":"熊童子","latinName":"Cotyledon tomentosa","synonyms":["小熊"],"family":"景天科银波锦属","origin":"南非"}','{"category":"多肉植物","growthHabit":"常绿性肉质灌木","flowerColor":"橙红色","floweringSeason":"夏季至秋季","fragrance":"无","landscapeUse":"窗台、桌面趣味型盆栽","potSuitable":true,"symbolism":"纯真、可爱"}','{"careDifficulty":"较高","lightRequirement":"全日照至半日照","waterRequirement":"耐旱，极易掉叶","temperature":"15-25℃","humidity":"干燥通风","soilRequirement":"颗粒比例至少70%的多肉土","droughtTolerance":"强","shadeTolerance":"一般","coldTolerance":"极弱，低于5℃易冻死","watering":"见干见湿，夏季需完全断水并保持极端通风","fertilizing":"春、秋生长期每2个月施肥一次","pruning":"可剪取侧芽进行扦插","propagation":"播种、扦插（叶插极难成功）","pests":"蚧壳虫、根腐病","safetyInfo":"无毒","specialNotes":"叶片上的红指甲是最大看点，忌高温多湿，夏季极易''露点''掉叶"}','2026-01-24 09:11:20',NULL);
INSERT INTO "plants" VALUES('ShanDiMeiGui','山地玫瑰','多肉植物','较高','{"name":"山地玫瑰","standard_name":"山地玫瑰","latinName":"Greenovia","synonyms":["永不凋谢的绿玫瑰"],"family":"景天科莲花掌属","origin":"加那利群岛"}','{"category":"多肉植物","growthHabit":"多年生肉质草本","flowerColor":"黄色","floweringSeason":"春末夏初","fragrance":"无","landscapeUse":"特色盆栽、多肉组合中心","potSuitable":true,"symbolism":"永恒的爱"}','{"careDifficulty":"较高","lightRequirement":"全日照至半日照，夏季休眠期避光","waterRequirement":"极怕积水，夏季强制休眠必须断水","temperature":"10-25℃","humidity":"干燥通风","soilRequirement":"排水极佳的泥炭颗粒混合土","droughtTolerance":"极强","shadeTolerance":"弱","coldTolerance":"一般，越冬温度建议5℃以上","watering":"生长期见干即浇，夏季休眠后叶片闭合时严控水","fertilizing":"生长期可施一次缓释肥","pruning":"休眠后清理外围干枯叶片","propagation":"侧芽分株、播种","pests":"蚧壳虫","safetyInfo":"无毒","specialNotes":"夏季休眠时叶片紧缩成玫瑰花苞状，美轮美奂"}','2026-01-24 09:11:20',NULL);
INSERT INTO "plants" VALUES('TaoDan','桃蛋','多肉植物','中等','{"name":"桃蛋","standard_name":"桃之卵","latinName":"Graptopetalum amethystinum","synonyms":["桃之卵"],"family":"景天科风车草属","origin":"墨西哥"}','{"category":"多肉植物","growthHabit":"多年生肉质草本","flowerColor":"淡粉色或星状花","floweringSeason":"夏季","fragrance":"无","landscapeUse":"悬垂盆栽、粉紫色调景观","potSuitable":true,"symbolism":"温润如玉"}','{"careDifficulty":"中等","lightRequirement":"喜全日照，光照足叶片肥厚粉嫩","waterRequirement":"极度耐旱，水多易化水掉叶","temperature":"15-28℃","humidity":"保持干燥","soilRequirement":"全颗粒或高颗粒土（80%+）","droughtTolerance":"极强","shadeTolerance":"差（极易徒长变丑）","coldTolerance":"一般，低于5℃需保暖","watering":"叶片发蔫发皱再补充水分","fertilizing":"生长期底肥即可，不建议多追肥","pruning":"由于易群生，可适当疏剪枝芽","propagation":"叶插（成功率极高）、扦插","pests":"煤烟病、叶班病","safetyInfo":"无毒","specialNotes":"控水是圆润的关键，忌叶面喷水"}','2026-01-24 09:11:20',NULL);
INSERT INTO "plants" VALUES('FeiCuiJing','翡翠景天','多肉植物','中等','{"name":"翡翠景天","standard_name":"翡翠景天","latinName":"Sedum morganianum","synonyms":["玉缀","新玉缀","驴尾"],"family":"景天科景天属","origin":"墨西哥"}','{"category":"多肉植物","growthHabit":"亚灌木状多年生草本","flowerColor":"粉红色至红色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"高挂篮种植、瀑布流多肉墙","potSuitable":true,"symbolism":"丰硕、连绵不断"}','{"careDifficulty":"中等","lightRequirement":"喜光照，耐半阴","waterRequirement":"耐旱，忌积水入心","temperature":"15-28℃","humidity":"适应环境","soilRequirement":"疏松透气的沙质填料","droughtTolerance":"强","shadeTolerance":"强","coldTolerance":"中等（耐5-8℃）","watering":"干透浇透，宁干勿湿","fertilizing":"施加缓释肥，生长旺季可追施少量磷肥","pruning":"剪除老化枯败的枝条基部","propagation":"叶插、枝条扦插（极易活）","pests":"蚧壳虫、蚜虫","safetyInfo":"无毒","specialNotes":"叶片非常易脱落，移动盆器时需极其小心"}','2026-01-24 09:11:20',NULL);
INSERT INTO "plants" VALUES('LuHui','芦荟','多肉植物','简单','{"name":"芦荟","standard_name":"芦荟","latinName":"Aloe vera","synonyms":["翠叶芦荟","油葱"],"family":"阿福花科芦荟属","origin":"地中海地区"}','{"category":"多肉植物","growthHabit":"多年生常绿肉质草本","flowerColor":"橙黄色、红色","floweringSeason":"夏季","fragrance":"无明显香味","landscapeUse":"盆栽观赏、药用价值、室内净化","potSuitable":true,"symbolism":"自尊自信、顽强的一生"}','{"careDifficulty":"简单","lightRequirement":"喜充足日照，不耐阴","waterRequirement":"极耐旱，忌积水","temperature":"20-30℃","humidity":"保持干燥","soilRequirement":"排水良好的沙壤土","droughtTolerance":"极强","shadeTolerance":"中等","coldTolerance":"较差（5℃以上）","watering":"一个月浇透1-2次即可","fertilizing":"每年春季施一次肥","pruning":"剥除干枯底叶","propagation":"分蘖繁殖","pests":"炭疽病","safetyInfo":"部分品种有毒，药用需遵医嘱","specialNotes":"夜间吸收二氧化碳释放氧气"}','2026-01-24 09:11:20',NULL);
INSERT INTO "plants" VALUES('XianRenZhang','仙人掌','多肉植物','简单','{"name":"仙人掌","standard_name":"仙人掌","latinName":"Opuntia dillenii","synonyms":["仙巴掌","火掌"],"family":"仙人掌科仙人掌属","origin":"热带美洲"}','{"category":"多肉植物","growthHabit":"肉质灌木","flowerColor":"黄色、橙色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"岩石园、篱笆墙、干旱景观","potSuitable":true,"symbolism":"坚强、刚毅"}','{"careDifficulty":"简单","lightRequirement":"喜强光照，不耐荫蔽","waterRequirement":"极耐干旱，怕积水涝灾","temperature":"20-35℃","humidity":"低湿度环境","soilRequirement":"园土掺入大量粗砂、碎砖","droughtTolerance":"极强","shadeTolerance":"低","coldTolerance":"一般，部分品种可耐短暂霜冻","watering":"夏季少量，冬季停水","fertilizing":"生长期每季施一次薄肥","pruning":"剪除老化、病虫害受损的分节","propagation":"扦插分节、播种","pests":"介壳虫、红蜘蛛","safetyInfo":"具锐利长刺，避免接触","specialNotes":"极易繁殖，生长迅速"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('HuangJinQingSuo','黄金庆松','多肉植物','容易','{"name":"黄金庆松","standard_name":"若绿","latinName":"Crassula muscosa","synonyms":["黄金若绿"],"family":"景天科青锁龙属","origin":"南非"}','{"category":"多肉植物","growthHabit":"半直立性肉质草本","flowerColor":"淡黄绿色","floweringSeason":"不定期","fragrance":"无","landscapeUse":"微型组合盆栽、多肉拼盘点缀","potSuitable":true,"symbolism":"青翠欲滴、生机勃勃"}','{"careDifficulty":"容易","lightRequirement":"充足光照，缺少光照叶片会松散变绿","waterRequirement":"中等，见干再浇","temperature":"15-28℃","humidity":"干燥、通风好","soilRequirement":"沙质微酸性疏松土","droughtTolerance":"强","shadeTolerance":"中等（易徒长）","coldTolerance":"较弱，建议5℃以上越冬","watering":"生长季节保持微潮，冬季严格控水","fertilizing":"施加缓释肥，生长频率高时可追肥","pruning":"需勤打顶以促进分枝密集","propagation":"扦插繁殖（极易活）","pests":"蚜虫","safetyInfo":"无毒","specialNotes":"叶片细小鳞片状紧密包围茎干，如同缩小版的松树"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('AiLian','爱之蔓','多肉植物','中等','{"name":"爱之蔓","standard_name":"吊灯花","latinName":"Ceropegia woodii","synonyms":["心蔓"],"family":"夹竹桃科吊灯花属","origin":"南非"}','{"category":"多肉植物","growthHabit":"多年生常绿攀援性草本","flowerColor":"紫褐色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"垂悬挂盆、浪漫表白景观","potSuitable":true,"symbolism":"心心相印、爱意绵绵"}','{"careDifficulty":"中等","lightRequirement":"半阴环境，忌强烈日光曝晒","waterRequirement":"耐旱，忌积水，根部有块茎","temperature":"18-28℃","humidity":"适应环境","soilRequirement":"疏松、肥沃的通用型营养土","droughtTolerance":"极强","shadeTolerance":"极强","coldTolerance":"弱（10℃以上）","watering":"土表发干再浇透，冬季严格控水","fertilizing":"生长期每两月施一次水溶肥","pruning":"当藤蔓过长可剪短诱导分枝","propagation":"珠芽扦插、枝条扦插","pests":"蚜虫","safetyInfo":"无毒","specialNotes":"茎蔓具有特色的心形肉质小叶及独特的项链感"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('FaShi','法师','多肉植物','容易','{"name":"法师","standard_name":"黑法师","latinName":"Aeonium arboreum ''Atropurpureum''","synonyms":["黑莲掌"],"family":"景天科莲花掌属","origin":"摩洛哥、地中海"}','{"category":"多肉植物","growthHabit":"多年生肉质灌木","flowerColor":"黄色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"个性盆栽、地中海风花境","potSuitable":true,"symbolism":"高贵、神秘"}','{"careDifficulty":"容易","lightRequirement":"喜光照充足，夏季高温需遮阴","waterRequirement":"耐旱，不耐积水","temperature":"15-25℃","humidity":"喜通风环境","soilRequirement":"泥炭颗粒土","droughtTolerance":"高","shadeTolerance":"中等（缺光叶片变绿）","coldTolerance":"一般，冬季5℃以上","watering":"生长旺季保持微潮，由于夏季休眠需显著控水","fertilizing":"生长期底肥即可","pruning":"可剪去过长枝芽促使母桩变壮","propagation":"扦插繁殖","pests":"蚧壳虫","safetyInfo":"无毒","specialNotes":"颜色深浅随阳光强烈程度变化变化"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('HongDiMao','红帝玉','多肉植物','困难','{"name":"红帝玉","standard_name":"红帝玉","latinName":"Pleiospilos nelii ''Royal Flush''","synonyms":["帝玉"],"family":"番杏科对叶花属","origin":"南非（园艺种）"}','{"category":"多肉植物","growthHabit":"多年生肉质草本","flowerColor":"紫红色","floweringSeason":"冬春季","fragrance":"无","landscapeUse":"微型精品盆栽","potSuitable":true,"symbolism":"奇妙的进化"}','{"careDifficulty":"困难","lightRequirement":"全日照环境，避免夏季正午强光","waterRequirement":"极其耐旱，过湿必死","temperature":"15-25℃","humidity":"通风透气","soilRequirement":"全石颗粒、粗砂辅以极少养分土","droughtTolerance":"极强","shadeTolerance":"极低","coldTolerance":"较弱，建议保持在10℃以上","watering":"生长季节极少量点喷，蜕皮季节强制停水","fertilizing":"通常不建议人工施肥","pruning":"无需人工修剪","propagation":"播种","pests":"根腐病","safetyInfo":"无毒","specialNotes":"属于''石头的伪装者''，对栽培介质干爽程度要求苛刻"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('HuangJiaLongSheLan','皇家龙舌兰','多肉植物','简单','{"name":"皇家龙舌兰","standard_name":"龙舌兰","latinName":"Agave victoriae-reginae","synonyms":["笹之雪"],"family":"天门冬科龙舌兰属","origin":"墨西哥"}','{"category":"多肉植物","growthHabit":"多年生常绿肉质草本","flowerColor":"乳黄色（花后死亡）","floweringSeason":"极其罕见，可能数十年一次","fragrance":"无","landscapeUse":"精致盆栽、干旱岩石景观","potSuitable":true,"symbolism":"坚持、等待、辉煌的一瞬"}','{"careDifficulty":"简单","lightRequirement":"全日照至半日照","waterRequirement":"极耐旱，生长季表层土干透后再浇水","temperature":"15-30℃","humidity":"干燥环境","soilRequirement":"砂质排水壤土","droughtTolerance":"极强","shadeTolerance":"中等","coldTolerance":"较强（部分耐受-5℃）","watering":"低频高量，冬季可断水","fertilizing":"每年春季通用型底肥一次","pruning":"基本无需修剪","propagation":"侧芽分株","pests":"龙舌兰象甲、介壳虫","safetyInfo":"汁液具有高刺激性，避免入眼","specialNotes":"生长极其缓慢，株型呈完美的球状几何美感"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('FaCaiShu','发财树','室内观叶植物','中等','{"name":"发财树","standard_name":"马拉巴栗","latinName":"Pachira aquatica","synonyms":["瓜栗"],"family":"锦葵科瓜栗属","origin":"美洲热带"}','{"category":"室内观叶植物","growthHabit":"常绿乔木","flowerColor":"丝状淡黄色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"室内大型盆栽、开业贺礼屏风植物","potSuitable":true,"symbolism":"招财进宝、兴旺发达"}','{"careDifficulty":"中等","lightRequirement":"散射光环境，过度暴晒会灼伤叶片","waterRequirement":"耐旱怕涝，忌盆底积水","temperature":"20-30℃","humidity":"中等湿度","soilRequirement":"疏松、肥沃的沙质混合腐叶土","droughtTolerance":"强","shadeTolerance":"强","coldTolerance":"极低（10℃以下易冻死）","watering":"由于通常主干肥大有储水能力，一个月浇透一次即可","fertilizing":"生长期每月追施磷钾轻量液肥","pruning":"生长期可摘心控制株高并诱导侧枝","propagation":"播种、扦插、压条","pests":"红蜘蛛、介壳虫","safetyInfo":"无毒","specialNotes":"最常见的''杀手''原因是由于浇水太勤导致的烂根"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('SanTieHuan','散尾葵','室内观叶植物','中等','{"name":"散尾葵","standard_name":"散尾葵","latinName":"Dypsis lutescens","synonyms":["黄椰子","紫葵"],"family":"棕榈科金果榔属","origin":"马达加斯加"}','{"category":"室内观叶植物","growthHabit":"丛生阔叶小乔木","flowerColor":"金黄色（罕见）","floweringSeason":"春夏季","fragrance":"无","landscapeUse":"室内通透感配置、大型客厅装饰、热带风格","potSuitable":true,"symbolism":"四面腾飞、柔美活泼"}','{"careDifficulty":"中等","lightRequirement":"明亮散射光，直射光叶尖会发焦","waterRequirement":"喜高湿与均衡供水","temperature":"20-28℃","humidity":"高空气湿度（需勤喷雾）","soilRequirement":"微酸性、多有机质的轻质填料","droughtTolerance":"一般","shadeTolerance":"一般（需一定亮光）","coldTolerance":"极差，建议不低于15℃","watering":"见干即浇，不可彻底干透","fertilizing":"生长期每月补充一次含氮较高的复合肥","pruning":"剪除发黄、干尖的较老叶鞘","propagation":"分株","pests":"红蜘蛛、介壳虫","safetyInfo":"无毒","specialNotes":"具有''天然加湿器''之称，能有效增加空气湿度"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('DiaoLan','吊兰','室内观叶植物','简单','{"name":"吊兰","standard_name":"吊兰","latinName":"Chlorophytum comosum","synonyms":["挂兰","兰草"],"family":"门冬科吊兰属","origin":"南非热带及亚热带"}','{"category":"室内观叶植物","growthHabit":"多年生常绿宿根草本","flowerColor":"白色","floweringSeason":"夏季","fragrance":"微香","landscapeUse":"悬挂装饰、除甲醛担当","potSuitable":true,"symbolism":"宁静、从容、天真"}','{"careDifficulty":"简单","lightRequirement":"半阴环境，强光照叶色会变淡","waterRequirement":"喜微湿，耐旱能力尚可","temperature":"15-28℃","humidity":"喜高空气湿度（防干尖）","soilRequirement":"排水良好且肥沃的疏松土质","droughtTolerance":"强（因有肉质块根）","shadeTolerance":"极强","coldTolerance":"一般，冬季建议移入室内维持在5℃以上","watering":"春秋见干即浇，夏季适当喷雾工作","fertilizing":"施肥过多易断根，每季度一次轻量复合肥即可","pruning":"定期剪短走茎，诱发子株繁衍","propagation":"分株、走茎子株直接种植","pests":"极少","safetyInfo":"无毒","specialNotes":"吸附室内一氧化碳及甲醛的高手，卧室首选"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('XianNyuHeZhuYu','仙女鹤竹芋','室内观叶植物','较高','{"name":"仙女鹤竹芋","standard_name":"仙女鹤竹芋","latinName":"Calathea sanderiana","synonyms":["青苹果竹芋","红羽竹芋"],"family":"竹芋科肖竹芋属","origin":"南非热带"}','{"category":"室内观叶植物","growthHabit":"常绿大型草本","flowerColor":"白、紫色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"大型客厅、商业中心艺术化点缀","potSuitable":true,"symbolism":"独立、独特眼光"}','{"careDifficulty":"较高","lightRequirement":"中等散射光，避开直射强光","waterRequirement":"必须维持土壤均衡湿润，严忌盆内干旱（死因首位）","temperature":"18-25℃","humidity":"极高浓度湿度（需持续喷雾或加湿器）","soilRequirement":"保水性号且疏松的腐殖质土壤","droughtTolerance":"极差","shadeTolerance":"中等","coldTolerance":"不耐寒（15℃以下停止生长并易受损）","watering":"表土微干约1CM处即补水，冬季控制频率","fertilizing":"每月追施一次稀薄液肥","pruning":"剪除由于环境干燥导致的发黑卷边叶子","propagation":"分株","pests":"红蜘蛛","safetyInfo":"无毒","specialNotes":"夜晚叶片会合拢，如同少女祈祷祈祷"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('WenZhu','文竹','室内观叶植物','中等','{"name":"文竹","standard_name":"文竹","latinName":"Asparagus setaceus","synonyms":["云片竹","山草"],"family":"门冬科天门冬属","origin":"南非东部至南部"}','{"category":"室内观叶植物","growthHabit":"常绿半蔓性多年生草本","flowerColor":"白色","floweringSeason":"秋季（极罕见）","fragrance":"微香","landscapeUse":"书房盆景、案头布置、切叶插花配材","potSuitable":true,"symbolism":"文雅、永恒友谊"}','{"careDifficulty":"中等","lightRequirement":"喜半阴，忌强光长时间直射","waterRequirement":"既怕旱又怕涝，根部肉质易腐","temperature":"15-25℃","humidity":"喜高空气湿度（特别是北方的冬天需勤加湿）","soilRequirement":"通透性好的腐叶含沙土","droughtTolerance":"一般","shadeTolerance":"极强（过于阴暗会导致分枝细弱发黄）","coldTolerance":"不耐寒（冬季控水并维持5℃以上）","watering":"盆土表面干后再浇透，勤向羽叶喷雾工作","fertilizing":"施肥忌浓，春秋季每月施稀薄复合肥水一次","pruning":"需勤剪枯枝并适当回缩过长蔓生茎","propagation":"播种、分株、扦插","pests":"介壳虫、红蜘蛛","safetyInfo":"无毒","specialNotes":"忌油烟或受废气、蚊香污染"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('LvLuo','绿萝','室内观叶植物','极易','{"name":"绿萝","standard_name":"绿萝","latinName":"Epipremnum aureum","synonyms":["黄金葛","魔鬼藤"],"family":"天南星科麒麟叶属","origin":"所罗门群岛、东南亚"}','{"category":"室内观叶植物","growthHabit":"多年生常绿攀援藤本","flowerColor":"隐头花序，极罕见","floweringSeason":"秋季（野外）","fragrance":"无","landscapeUse":"悬吊盆栽、绿萝柱、水培装饰、除甲醛","potSuitable":true,"symbolism":"坚韧、守望幸福"}','{"careDifficulty":"极易","lightRequirement":"散射光最佳，耐阴性极强（光太强会灼伤）","waterRequirement":"喜水，耐旱力也较强","temperature":"15-30℃","humidity":"中高湿度","soilRequirement":"轻质易透气介质，也可直接纯水养","droughtTolerance":"较强","shadeTolerance":"极强","coldTolerance":"极弱，冬季尽量保持在10℃以上","watering":"土培见干见湿，水培每周换水清洗容器","fertilizing":"通用液体肥每月一次喷施或随水冲施即可","pruning":"当藤蔓过长可剪掉分插新盆，也能诱发更茂密的叶芽","propagation":"扦插（遇水、遇土即活）","pests":"介壳虫（极少出现）","safetyInfo":"汁液有毒，禁止误食以免引起过敏或咽痛","specialNotes":"著名的''生命之花''，是所有养宠新手的信心之选"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('AiShengFanQie','矮生番茄','中药材/蔬果类','中等','{"name":"矮生番茄","standard_name":"矮生小番茄","latinName":"Solanum lycopersicum ''Dwarf''","synonyms":["樱桃番茄","盆栽圣女果"],"family":"茄科番茄属","origin":"南美洲（现代园艺种）"}','{"category":"中药材/蔬果类","growthHabit":"一年生直立草本","flowerColor":"黄色","floweringSeason":"定植后40-60天开始","fragrance":"叶片有植物特有气息","landscapeUse":"阳台菜园、兼具观赏与食用盆栽","potSuitable":true,"symbolism":"红火生活、丰收"}','{"careDifficulty":"中等","lightRequirement":"喜充足日照","waterRequirement":"喜水量大但盆土需排水好","temperature":"20-30℃","humidity":"中等湿度","soilRequirement":"有机质丰富的肥沃重质营养土","droughtTolerance":"差（缺水会导致果实开裂或落蕾）","shadeTolerance":"极低（不足会导致光长个不开花）","coldTolerance":"极弱，惧霜冻（低于10℃停止生发）","watering":"早晚观察盆土，挂果期不能缺水","fertilizing":"定植施底肥，开花挂果后每月两次高磷钾肥","pruning":"摘除老化下层叶片，疏减过密花球（矮生种通常不需打侧芽）","propagation":"播种繁殖","pests":"潜叶蝇、蚜虫、晚疫病","safetyInfo":"其果实可食用，绿色植株部分含有生物碱不可误食","specialNotes":"需立简易支架防止倒伏，通过摇晃植株辅助授粉"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('XiangXunXunYiCao','香薰薰衣草','中药材/蔬果类','较高','{"name":"香薰薰衣草","standard_name":"狭叶薰衣草","latinName":"Lavandula angustifolia","synonyms":["真薰衣草","英国薰衣草"],"family":"唇形科薰衣草属","origin":"地中海沿岸"}','{"category":"中药材/蔬果类","growthHabit":"多年生常绿半灌木","flowerColor":"蓝色、深紫色","floweringSeason":"夏季","fragrance":"极强烈舒缓香气，安神镇静","landscapeUse":"芳香园、香料植物盆栽、干花制作","potSuitable":true,"symbolism":"等待爱情、纯洁、奉献"}','{"careDifficulty":"较高","lightRequirement":"全日照环境，夏季忌高温多湿环境","waterRequirement":"耐旱力极强，怕长期积湿（导致黑茎烂根）","temperature":"15-25℃","humidity":"干燥、高透风率环境","soilRequirement":"轻质、碱性排水优异的沙砾土质","droughtTolerance":"极强","shadeTolerance":"低（阴暗会导致植株衰退并枯死）","coldTolerance":"极强（部分品种可耐受极端低温）","watering":"土完全干后等3-5天再浇，盆底拒绝积水","fertilizing":"耐瘠薄，每年春天施加少量骨粉即可","pruning":"每年花谢后进行回缩修剪，防止其木质化严重导致的中空","propagation":"扦插繁殖、播种","pests":"褐斑病、蚜虫","safetyInfo":"可药用、护肤、制作茶饮、精油提取提取物","specialNotes":"不建议种植在潮湿的海边或极高雨水地带地带"}','2026-01-24 09:11:21',NULL);
INSERT INTO "plants" VALUES('JiuCai','韭菜','中药材/蔬果类','简单','{"name":"韭菜","standard_name":"韭菜","latinName":"Allium tuberosum","synonyms":["起阳草","长生韭"],"family":"石蒜科葱属","origin":"东亚、中国北方"}','{"category":"中药材/蔬果类","growthHabit":"多年生宿根草本","flowerColor":"白色簇生伞房花序","floweringSeason":"夏秋季","fragrance":"强烈蒜香味（花可食用）","landscapeUse":"家庭菜圃、阳台盆栽、地被覆盖","potSuitable":true,"symbolism":"长久友谊、生命力"}','{"careDifficulty":"简单","lightRequirement":"喜光也耐半阴，光照充实口感佳","waterRequirement":"水量需求中等偏高，忌干旱导致叶肉变老缩","temperature":"15-25℃","humidity":"适应环境","soilRequirement":"疏松、肥沃且高有机质的混合中性土","droughtTolerance":"中等","shadeTolerance":"中等","coldTolerance":"极强（根茎可耐受极端地面冰冻并来年复发）","watering":"保持土表微潮，夏季早晚各补一次水","fertilizing":"每次剪收后必须重施含氮为主的速效肥一次一次","pruning":"剪收即修剪，保留地面3-5CM处切断","propagation":"播种、分根、移植","pests":"韭蛆（杀手）、蓟马","safetyInfo":"著名的食用蔬菜，具补肾壮阳之功之功","specialNotes":"一经栽植可以连续多年采收，属于家庭盆栽性价比之首"}','2026-01-24 09:11:22',NULL);
INSERT INTO "plants" VALUES('LuoLe','罗勒','中药材/蔬果类','简单','{"name":"罗勒","standard_name":"罗勒","latinName":"Ocimum basilicum","synonyms":["九层塔","金不换"],"family":"唇形科罗勒属","origin":"印度、东南亚热带"}','{"category":"中药材/蔬果类","growthHabit":"一年生直立草本","flowerColor":"白色、淡紫色","floweringSeason":"夏季","fragrance":"独特辛辣甜香味，极诱人","landscapeUse":"西餐香料园、驱蚊盆栽、厨房阳台","potSuitable":true,"symbolism":"神圣、好运、永恒友谊"}','{"careDifficulty":"简单","lightRequirement":"喜充足日照，耐热力好","waterRequirement":"喜湿润，怕积水涝根","temperature":"18-35℃","humidity":"中等至高湿度环境","soilRequirement":"肥沃、排水通畅极其良好的轻质腐叶土","droughtTolerance":"差（一旦脱水会迅速垂软）","shadeTolerance":"低（阴暗会导致香气变淡并生病）","coldTolerance":"极差（低于10℃即停止增长并易冻烂）","watering":"勤观察，夏季甚至每日两次补水，避开中午直灌","fertilizing":"施加底肥即可，生长期每半月追施少量液态肥","pruning":"经常摘下顶叶食用不仅能防开花早衰，还能诱发密集分枝枝","propagation":"播种、扦插（自繁极快）","pests":"蚜虫、粉虱","safetyInfo":"著名的食用香料，西餐不可缺少之配角","specialNotes":"开花后口感会变差，建议看到花蕾即掐断以维持美味"}','2026-01-24 09:11:22',NULL);
INSERT INTO "plants" VALUES('TianTangNiao','天堂鸟','热带花卉','容易','{"name":"天堂鸟","standard_name":"鹤望兰","latinName":"Strelitzia reginae","synonyms":["极乐鸟花"],"family":"鹤望兰科鹤望兰属","origin":"南非"}','{"category":"热带花卉","growthHabit":"多年生常绿草本","flowerColor":"橙黄色、深蓝色、紫色","floweringSeason":"四季可开花，以冬春为主","fragrance":"无","landscapeUse":"由于叶片美如羽扇，亦作为室内大型观叶植物、高档切花","potSuitable":true,"symbolism":"吉祥、幸福、长寿"}','{"careDifficulty":"容易","lightRequirement":"喜光，需充足阳光才能开花，夏季遮阴","waterRequirement":"喜湿润，忌积水，肉质根部怕涝","temperature":"15-25℃","humidity":"中高湿度","soilRequirement":"肥沃、深厚、排水良好的粘质填料","droughtTolerance":"中等","shadeTolerance":"中等（耐半阴，但不开花）","coldTolerance":"极差（越冬建议10℃以上）","watering":"生长旺季保持湿润，冬季控水","fertilizing":"生长季每月施一次磷钾含量较高的肥","pruning":"剪除老叶和残花","propagation":"分株、播种","pests":"蚧壳虫、炭疽病","safetyInfo":"微毒，不可误食","specialNotes":"开花形状如仙鹤引颈，具有极高的艺术观赏价值"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('HongZhang','红掌','热带花卉','中等','{"name":"红掌","standard_name":"花烛","latinName":"Anthurium andraeanum","synonyms":["火鹤花","安祖花"],"family":"天南星科花烛属","origin":"南美洲热带雨林"}','{"category":"热带花卉","growthHabit":"多年生常绿草本","flowerColor":"鲜红色、粉色、白色（佛焰苞）","floweringSeason":"全年均可开花","fragrance":"无","landscapeUse":"室内高档盆花、开业庆典花篮、切花","potSuitable":true,"symbolism":"大展宏图、热情、热血"}','{"careDifficulty":"中等","lightRequirement":"明亮散射光，忌阳光直晒（灼烧叶片）","waterRequirement":"喜高湿环境，盆土微湿忌积水","temperature":"18-28℃","humidity":"高湿度（＞70%），需经常向周围喷雾","soilRequirement":"极其疏松透气的泥炭土或水苔","droughtTolerance":"弱","shadeTolerance":"强","coldTolerance":"极弱（冬季不低于15℃）","watering":"见干见湿，保持高空气湿度是关键","fertilizing":"开花季磷钾肥需求大，每月追肥两次","pruning":"剪除发黄的老叶和谢掉的残花","propagation":"分株、组培","pests":"红蜘蛛、介壳虫","safetyInfo":"汁液有刺激性，严禁误食","specialNotes":"其''红色花瓣''其实是佛焰苞，真正的花是中间那根黄柱子"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('PinZhongLongSheLan','笹之雪','精品多肉','简单','{"name":"笹之雪","standard_name":"笹之雪","latinName":"Agave victoriae-reginae","synonyms":["厚叶龙舌兰"],"family":"天门冬科龙舌兰属","origin":"墨西哥"}','{"category":"精品多肉","growthHabit":"多年生常绿肉质草本","flowerColor":"淡黄绿色","floweringSeason":"极罕见（通常数十年一次）","fragrance":"无","landscapeUse":"极具几何几何美感的收藏级盆栽、现代极简景观","potSuitable":true,"symbolism":"坚韧不拔、独特、等待"}','{"careDifficulty":"简单","lightRequirement":"喜强光照","waterRequirement":"极耐旱","temperature":"15-30℃","humidity":"干燥通风","soilRequirement":"砂石等矿物质比例高的多肉土","droughtTolerance":"极强","shadeTolerance":"弱","coldTolerance":"中等（短时耐受0℃）","watering":"彻底干透再浇透，生长季也就一个月一两次","fertilizing":"不喜由于氮肥过多引起其徒长，春秋底肥即可","pruning":"由于生长缓慢，基本不需修剪","propagation":"侧芽分株","pests":"龙舌兰象甲、象鼻虫","safetyInfo":"叶尖有黑硬尖刺，汁液对皮肤有刺激","specialNotes":"叶缘上的白色线条是自然留下的印记，也是其珍贵身份的象征"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('BaiHeZhuYu','白鹤芋','室内观叶植物','容易','{"name":"白鹤芋","standard_name":"白掌","latinName":"Spathiphyllum kochii","synonyms":["一帆风顺"],"family":"天南星科白鹤芋属","origin":"哥伦比亚"}','{"category":"室内观叶植物","growthHabit":"多年生常绿草本","flowerColor":"白色（佛焰苞）","floweringSeason":"5-8月","fragrance":"无","landscapeUse":"室内装饰、水培观赏、除甲醛担当","potSuitable":true,"symbolism":"一帆风顺、事业有成"}','{"careDifficulty":"容易","lightRequirement":"喜半阴，忌强光直射","waterRequirement":"喜湿润，不耐积水","temperature":"18-28℃","humidity":"中高湿度","soilRequirement":"疏松、肥沃的腐质质土壤","droughtTolerance":"差（一旦缺水叶片会由于萎蔫全部倒伏）","shadeTolerance":"极强","coldTolerance":"弱，冬季不低于10℃","watering":"见干见湿，生长期需常对叶片喷水","fertilizing":"生长季每月施一次液体薄肥","pruning":"剪除凋谢变色的残花和老叶","propagation":"分株","pests":"红蜘蛛、蚜虫","safetyInfo":"具有一定毒性，不可误食","specialNotes":"吸附室内废气及粉尘能力强，适合摆放在空气流通处"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('HongBo','红波','仙人掌类','容易','{"name":"红波","standard_name":"红波","latinName":"Gymnocalycium mihanovichii v. friedrichii ''Hibotan''","synonyms":["绯牡丹","红球仙人球"],"family":"仙人掌科裸萼球属","origin":"南美洲（园艺育种）"}','{"category":"仙人掌类","growthHabit":"球形仙人掌","flowerColor":"粉红色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"桌面小盆栽、嫁接组合艺术品","potSuitable":true,"symbolism":"红火生活、幸运"}','{"careDifficulty":"容易","lightRequirement":"喜光照，但忌烈日暴晒（红皮易伤）","waterRequirement":"耐旱","temperature":"15-28℃","humidity":"干燥通风","soilRequirement":"透气性极强的多肉专用混合介质","droughtTolerance":"极强","shadeTolerance":"中等","coldTolerance":"差，越冬维持在10℃以上","watering":"一个月一次即可，冬天绝对禁止盆土进水","fertilizing":"生长期可施一次轻量颗粒肥","pruning":"无需修剪","propagation":"由于自身由于缺乏叶绿素，必须通过嫁接繁殖（通常嫁接在量天尺上）","pests":"蚧壳虫、根结线虫","safetyInfo":"具细刺，避免儿童触摸","specialNotes":"它不能独立地生长在土壤中（除极少绿肉品种），必须通过嫁接存活"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('HuBianShiXian','虎边石莲','精品多肉','容易','{"name":"虎边石莲","standard_name":"吉娃莲","latinName":"Echeveria chihuahuaensis","synonyms":["吉娃娃"],"family":"景天科拟石莲花属","origin":"墨西哥"}','{"category":"精品多肉","growthHabit":"多年生肉质草本","flowerColor":"红黄色","floweringSeason":"春末","fragrance":"无","landscapeUse":"单盆观赏、多肉景观台点缀","potSuitable":true,"symbolism":"可爱、灵动"}','{"careDifficulty":"容易","lightRequirement":"喜全日照，光照充足时叶尖变绯红","waterRequirement":"耐旱，忌积水","temperature":"15-26℃","humidity":"空气流通干燥","soilRequirement":"疏松、透气的砂质壤土","droughtTolerance":"极强","shadeTolerance":"弱（极易徒长变丑）","coldTolerance":"弱，低于5℃需保暖","watering":"干透浇透，宁干勿湿","fertilizing":"生长季每两三个月施一点缓释颗粒肥","pruning":"剪除底部干老残叶子","propagation":"叶插、分株、播种","pests":"蚧壳虫、煤烟病","safetyInfo":"无毒","specialNotes":"颜值极高的普货之首，叶尖的红指甲是最大卖点"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('MiLan','米兰','室内观叶/香花','较高','{"name":"米兰","standard_name":"米仔兰","latinName":"Aglaia odorata","synonyms":["碎米兰","珠兰"],"family":"楝科米仔兰属","origin":"中国及东南亚"}','{"category":"室内观叶/香花","growthHabit":"常绿灌木","flowerColor":"黄色（如碎米粒）","floweringSeason":"夏季至秋季（温湿度适宜可常年开花）","fragrance":"醇厚清香、令人神清气爽","landscapeUse":"庭院点缀、室内香花盆栽","potSuitable":true,"symbolism":"爱家、谦逊、奉献"}','{"careDifficulty":"较高","lightRequirement":"喜充足日照，不耐阴阴","waterRequirement":"喜湿润忌积水积湿","temperature":"20-30℃","humidity":"中高湿度环境","soilRequirement":"微酸性、排水顺畅通透的腐殖质土壤","droughtTolerance":"差","shadeTolerance":"中等（耐半阴但严重影响生长与开花）","coldTolerance":"极差，冬季务必维持在10℃以上","watering":"春秋见干即浇，夏季早晚增加喷水增湿措施","fertilizing":"生长期多施氮磷混合颗粒肥","pruning":"剪除细弱枝，花后进行整形修剪","propagation":"扦插、高压繁殖","pests":"红蜘蛛、介壳虫","safetyInfo":"无毒","specialNotes":"肥料和阳光是其开花不断的两个关键维度维度"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('QianNiuHua','牵牛花','一年生花卉','容易','{"name":"牵牛花","standard_name":"牵牛","latinName":"Ipomoea nil","synonyms":["朝颜","喇叭花"],"family":"旋花科牵牛属","origin":"热带美洲（全球均有分布）"}','{"category":"一年生花卉","growthHabit":"一年生攀援草本","flowerColor":"蓝、紫、红、粉、白及复色","floweringSeason":"夏季至秋季","fragrance":"无","landscapeUse":"篱笆墙绿化、凉亭遮阴、容器盆栽","potSuitable":true,"symbolism":"名誉、爱情永固"}','{"careDifficulty":"容易","lightRequirement":"全日照","waterRequirement":"喜充足水分，不耐干旱","temperature":"20-30℃","humidity":"普通湿度环境","soilRequirement":"适应性强，对土壤不挑剔","droughtTolerance":"一般","shadeTolerance":"低","coldTolerance":"不耐寒（秋季枯萎自留种）","watering":"生长季每天早晚补水，保持湿润","fertilizing":"每两周施用一次稀薄复合肥","pruning":"摘心促进分枝生长，剪除受损藤蔓藤蔓","propagation":"播种繁殖（春季）","pests":"蚜虫、红蜘蛛、潜叶甲","safetyInfo":"其种子具一定药性，过量食用会导致腹痛腹痛","specialNotes":"清晨绽放傍晚凋谢凋谢，别名''朝颜''"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('AiBuGeng','矮牵牛','一二年生花卉','容易','{"name":"矮牵牛","standard_name":"矮牵牛","latinName":"Petunia hybrid","synonyms":["灵芝牡丹","碧冬茄"],"family":"茄科矮牵牛属","origin":"南美洲（现代杂交种）"}','{"category":"一二年生花卉","growthHabit":"多年生草本、常作一二年生栽培","flowerColor":"极为丰富（所有可见颜色及条纹）","floweringSeason":"春至晚秋常年不断","fragrance":"部分品种有微香味","landscapeUse":"露台吊挂盆、花坛中心配置、景观台点缀点缀","potSuitable":true,"symbolism":"安心、温暖、家庭凝聚"}','{"careDifficulty":"容易","lightRequirement":"须全日照","waterRequirement":"需水量巨大，但忌根部积水","temperature":"15-28℃","humidity":"中等湿度","soilRequirement":"肥沃、疏松透气排水极其流畅的营养介质","droughtTolerance":"差（缺水迅速枯萎倒伏）","shadeTolerance":"低","coldTolerance":"一般（北方越冬建议室内）","watering":"生长旺盛旺季保持每天浇透水","fertilizing":"著名的''吃肥机器''，每周补速效磷钾肥一次一次","pruning":"花谢后谢后残花必掐，长势过乱需进行''剃头''重剪重剪","propagation":"播种、扦插","pests":"蚜虫、红蜘蛛、灰霉病","safetyInfo":"无毒","specialNotes":"最适合阳台大面积制造''爆盆''美感的花卉花卉"}','2026-01-24 09:11:52',NULL);
INSERT INTO "plants" VALUES('HeHuaBatch4','荷花','水生植物','较高','{"name":"荷花","standard_name":"莲","latinName":"Nelumbo nucifera","synonyms":["莲花","芙蕖"],"family":"莲科莲属","origin":"亚洲热带和温带"}','{"category":"水生植物","growthHabit":"多年生水生草本","flowerColor":"红色、粉色、白色、紫色","floweringSeason":"夏季","fragrance":"清新淡雅","landscapeUse":"园林水景、盆缸种植（碗莲）","potSuitable":true,"symbolism":"纯洁、高雅、出淤泥而不染"}','{"careDifficulty":"较高","lightRequirement":"极喜全日照","waterRequirement":"必须长期浸没在水中，水位需稳定","temperature":"22-35℃","humidity":"中高湿度","soilRequirement":"肥沃的水生专用塘泥","droughtTolerance":"无","shadeTolerance":"极差","coldTolerance":"中等（地下根茎耐低温，但不可冻透）","watering":"始终保持水位高于土面5-10厘米","fertilizing":"定植后立叶长出可开始施用专用肥料","pruning":"剪除枯萎的浮叶和残花","propagation":"分藕（分株）、播种","pests":"蚜虫、斜纹夜蛾","safetyInfo":"无毒，莲藕与莲子可食用","specialNotes":"阳台种碗莲需要光照极其充足的南向位置"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('ShuiLianBatch4','睡莲','水生植物','中等','{"name":"睡莲","standard_name":"睡莲","latinName":"Nymphaea tetragona","synonyms":["子午莲"],"family":"睡莲科睡莲属","origin":"东亚、东南亚"}','{"category":"水生植物","growthHabit":"浮叶性水生草本","flowerColor":"白、红、粉、黄、蓝、紫色","floweringSeason":"夏秋季","fragrance":"有（清香）","landscapeUse":"水池点缀、室内透明容器水培搭配","potSuitable":true,"symbolism":"重生、纯洁、神圣"}','{"careDifficulty":"中等","lightRequirement":"喜全日照，不耐阴","waterRequirement":"需长期深水浸泡","temperature":"15-30℃","humidity":"中高湿度环境","soilRequirement":"轻质塘泥或肥沃粘土","droughtTolerance":"无","shadeTolerance":"低","coldTolerance":"耐寒品种可耐-5℃（地下部分），热带品种需保温","watering":"换水需分次进行，避免由于温差过大导致死苗","fertilizing":"生长旺季每两周施一次水生植物专用肥","pruning":"及时清除掉老化的浮叶和过剩的藻类","propagation":"分根、播种","pests":"水螟、蜗牛","safetyInfo":"无毒","specialNotes":"花朵具有白天绽放、夜晚闭合的习性"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('CaoMei','草莓','中药材/蔬果类','中等','{"name":"草莓","standard_name":"草莓","latinName":"Fragaria × ananassa","synonyms":["凤梨草莓","地莓"],"family":"蔷薇科草莓属","origin":"美洲（园艺种）"}','{"category":"中药材/蔬果类","growthHabit":"多年生常绿草本","flowerColor":"白色、粉色","floweringSeason":"春夏季（室内可提早）","fragrance":"无明显花香，果实浓郁甜香","landscapeUse":"垂悬盆栽、家庭果园、亲子科普种植","potSuitable":true,"symbolism":"甜蜜、诱惑、硕果累累"}','{"careDifficulty":"中等","lightRequirement":"喜充足日照","waterRequirement":"喜水怕涝，忌干旱","temperature":"15-25℃","humidity":"中等湿度","soilRequirement":"疏松、肥沃、排水良好的微酸性壤土","droughtTolerance":"差","shadeTolerance":"低","coldTolerance":"较强（根部耐受低温，但挂果期需温暖）","watering":"挂果期不可断水，浇水避开果实","fertilizing":"基肥需足，花果期追施磷钾水肥","pruning":"剪除干叶和病叶，及时掐掉冗余的走茎","propagation":"走茎压条（自繁极快）","pests":"红蜘蛛、蜗牛、灰霉病","safetyInfo":"无毒，食用前需清洗干净","specialNotes":"挂果需垫高，由于避免果实由于直接接触土壤而腐烂"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('LanMei','蓝莓','中药材/蔬果类','较高','{"name":"蓝莓","standard_name":"蓝莓","latinName":"Vaccinium corymbosum","synonyms":["笃斯越橘"],"family":"杜鹃花科越橘属","origin":"北美洲"}','{"category":"中药材/蔬果类","growthHabit":"常绿或落叶灌木","flowerColor":"白色或粉红色（钟状）","floweringSeason":"春季","fragrance":"淡香","landscapeUse":"阳台果园、灌木配置、秋季观红叶","potSuitable":true,"symbolism":"智慧之果、坚持"}','{"careDifficulty":"较高","lightRequirement":"全日照环境，夏季高温适当避暑","waterRequirement":"由于根系浅，必须保持土壤均衡润润忌干旱","temperature":"15-25℃","humidity":"中等湿度","soilRequirement":"绝对酸性土壤（pH 4.5-5.5），疏松且透气","droughtTolerance":"极差","shadeTolerance":"差","coldTolerance":"极强（温带品种需一定的冷积温才能结果）","watering":"盆土微干即浇，禁止使用高偏碱性水长期浇灌","fertilizing":"喜酸性肥，禁止使用含氯肥，春秋季追肥","pruning":"修剪交叉枝、病枝，保持冠形通风","propagation":"扦插繁殖、组培","pests":"介壳虫、鸟类（啄食果实）","safetyInfo":"无毒，食用需彻底洗净","specialNotes":"土壤酸度和冷积温是家庭盆栽蓝莓结果的两个门槛"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('OuYeZao','牛至','中药材/蔬果类','简单','{"name":"牛至","standard_name":"牛至","latinName":"Origanum vulgare","synonyms":["披萨草","野马郁兰"],"family":"唇形科牛至属","origin":"地中海地区"}','{"category":"中药材/蔬果类","growthHabit":"多年生草本或半灌木","flowerColor":"紫色或粉红色","floweringSeason":"夏季","fragrance":"辛辣、浓郁的草木混合香","landscapeUse":"厨房药草园、披萨伴侣、地被覆盖","potSuitable":true,"symbolism":"欢乐、健康"}','{"careDifficulty":"简单","lightRequirement":"必须全日照","waterRequirement":"超耐旱，忌积水入根","temperature":"15-30℃","humidity":"保持干燥通风","soilRequirement":"轻质沙壤、排水流畅通顺","droughtTolerance":"极强","shadeTolerance":"极低","coldTolerance":"极强（北方北方可露地越冬）","watering":"土表面彻底干后再浇水","fertilizing":"生长初季施缓释肥即可，不建议多由于","pruning":"开花前修剪叶片香气最浓，花后可大面积回剪","propagation":"播种、扦插、分株","pests":"极少病虫害","safetyInfo":"著名的食用香料","specialNotes":"由于其药草气息，具有天然的一定的驱虫作用"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('BaiLiXiang','百里香','中药材/蔬果类','一般','{"name":"百里香","standard_name":"百里香","latinName":"Thymus vulgaris","synonyms":["地椒","山椒"],"family":"唇形科百里香属","origin":"欧洲南部"}','{"category":"中药材/蔬果类","growthHabit":"常绿矮小灌木/匍匐草本","flowerColor":"淡紫色或粉色","floweringSeason":"夏季","fragrance":"极强烈草药浓香、除膻解腻","landscapeUse":"石园拼盘、牛排配搭园、家庭香盒窗台","potSuitable":true,"symbolism":"勇气、高洁"}','{"careDifficulty":"一般","lightRequirement":"极喜全光照","waterRequirement":"耐旱，忌积水尤其是闷热季节的高温积水","temperature":"15-25℃","humidity":"偏干通风","soilRequirement":"碱性或中性、砂质极通透土质","droughtTolerance":"强","shadeTolerance":"低","coldTolerance":"极强（-20℃仍可露地存活存活）","watering":"宁干勿湿，雨季需严防避雨防避雨","fertilizing":"每年初春施少量有机骨粉即可","pruning":"剪收嫩尖用于料理，冬季进行大幅由于修剪防木质老化","propagation":"扦插、分株","pests":"粉虱","safetyInfo":"常用西餐香料，安全安全安全性极高","specialNotes":"极怕由于根部不通风导致的海绵化腐烂"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('XueTieYu','雪铁芋','室内观叶植物','极简','{"name":"雪铁芋","standard_name":"金钱树","latinName":"Zamioculcas zamiifolia","synonyms":["金钱树","金币草"],"family":"天南星科雪铁芋属","origin":"非洲东部雨林"}','{"category":"室内观叶植物","growthHabit":"多年生常绿中草本植物","flowerColor":"佛焰苞，隐藏在叶柄基部","floweringSeason":"夏季（极罕见可用）","fragrance":"无","landscapeUse":"室内办公、商业场所招财开业盆栽、耐荫环境死角填充","potSuitable":true,"symbolism":"招财进宝、大吉大利"}','{"careDifficulty":"极简","lightRequirement":"喜散射光，耐阴，忌烈日暴晒","waterRequirement":"耐旱怕涝，其具有肉质主轴储水能力强","temperature":"20-32℃","humidity":"中等湿度","soilRequirement":"疏松、肥沃且极好由于排水性的砂质酸性填料","droughtTolerance":"极强","shadeTolerance":"极强","coldTolerance":"极弱（冬季必须维持在10℃以上）","watering":"一个月一次浇透即可，由于宁干勿湿不可频繁补水","fertilizing":"生长旺期每月补充一次通用通用型水溶肥","pruning":"由于定期剪除由于由于长期缺光或自然衰退导致的枯萎老枝","propagation":"分株、叶片直接扦插（极慢速度快）","pests":"褐斑病、介壳虫","safetyInfo":"其汁液含草酸钙，禁止误食以免灼伤皮肤或喉咙","specialNotes":"它是最耐阴的网红盆栽代表之一"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('XiangNiaoRu','橡皮树','室内观叶植物','容易','{"name":"橡皮树","standard_name":"印度榕","latinName":"Ficus elastica","synonyms":["印度橡胶树"],"family":"桑科榕属","origin":"印度、东南亚"}','{"category":"室内观叶植物","growthHabit":"常绿大乔木（盆栽可控）","flowerColor":"隐头花序，不明显","floweringSeason":"春夏季","fragrance":"无","landscapeUse":"大型客厅、玄关门厅、现代工业风家居装饰","potSuitable":true,"symbolism":"稳重、诚实、万古长青"}','{"careDifficulty":"容易","lightRequirement":"全日照至半日照","waterRequirement":"需水量中等，保持盆土微潮即可","temperature":"20-30℃","humidity":"中高湿度","soilRequirement":"肥沃、深厚、排水良好的土壤","droughtTolerance":"强","shadeTolerance":"极强","coldTolerance":"弱（10℃以下易落叶）","watering":"由于夏季早晚注意由于喷雾工作，由于盆土见干即浇","fertilizing":"生长季每月追施一次全素肥","pruning":"需通过由于摘心操作来控制由于生长高度并诱导由于侧芽萌发","propagation":"扦插繁殖、压条","pests":"蚧壳虫、炭疽病","safetyInfo":"白色汁液有毒，皮肤由于接触易由于过敏过敏","specialNotes":"巨大的叶片是净化粉尘的能手，需定期擦拭叶面叶面"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('MuBingChanGueZhu','竹节秋海棠','室内观叶/花卉','通常（对由于环境湿度敏感）','{"name":"竹节秋海棠","standard_name":"竹节秋海棠","latinName":"Begonia maculata","synonyms":["斑叶秋海棠","波点海棠"],"family":"秋海棠科秋海棠属","origin":"巴西热带山区"}','{"category":"室内观叶/花卉","growthHabit":"多年生常绿半灌木","flowerColor":"粉红色、白色（垂吊状）","floweringSeason":"四季均可能开花，以夏秋为主","fragrance":"无","landscapeUse":"网红时尚盆栽、室内氛围装饰、文艺摄影背景拍摄","potSuitable":true,"symbolism":"真诚、独特、相思"}','{"careDifficulty":"通常（对由于环境湿度敏感）","lightRequirement":"喜散射光线，忌烈日暴晒","waterRequirement":"喜水怕涝，保持土表湿润不干结即可","temperature":"18-28℃","humidity":"中高空气浓度湿度环境","soilRequirement":"轻质疏松且由于肥沃的通用泥炭混土","droughtTolerance":"差（干旱会落花落叶）","shadeTolerance":"中等","coldTolerance":"弱（宜在15℃以上环境生长避寒）","watering":"土表面微干即补充水分，保持由于环境湿度湿度","fertilizing":"生长期由于每两周施一次稀薄液肥，多磷钾由于","pruning":"剪去枯花并及时摘掉干枯的变褐色叶片","propagation":"扦插自繁（春季易成功）","pests":"白粉病、蚜虫","safetyInfo":"具有一定药性及由于轻微毒性，禁服","specialNotes":"其背后呈深红色的叶面与由于白波点是时尚界的宠儿宠物"}','2026-01-24 09:12:03',NULL);
INSERT INTO "plants" VALUES('NanGua','南瓜','蔬菜类/蒸菜','容易','{"name":"南瓜","standard_name":"南瓜","latinName":"Cucurbita moschata","synonyms":["倭瓜","番瓜"],"family":"葫芦科南瓜属","origin":"美洲热带"}','{"category":"蔬菜类/蒸菜","growthHabit":"一年生蔓生草本","flowerColor":"黄色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"菜园爬藤、大型容器种植、秋季景观展示","potSuitable":true,"symbolism":"丰收、吉祥"}','{"careDifficulty":"容易","lightRequirement":"极喜全日照，光照充足","waterRequirement":"喜湿润，生长高峰期需水量大","temperature":"18-32℃","humidity":"中等湿度","soilRequirement":"肥沃、深厚、排水良好的土壤","droughtTolerance":"中等","shadeTolerance":"低","coldTolerance":"极弱（不耐霜冻）","watering":"保持土壤湿润，果实膨大期加强水分供应","fertilizing":"重肥植物，底肥要足，后期施磷钾肥","pruning":"需压蔓、打顶，促进侧蔓结果","propagation":"播种","pests":"白粉病、蚜虫","safetyInfo":"无毒，花、嫩茎、果实皆可食用","specialNotes":"蒸制南瓜口感绵软，是健康蒸菜的首选素材"}','2026-01-24 09:16:31',NULL);
INSERT INTO "plants" VALUES('ShanYao','山药','中药材/蔬果/蒸菜','中等','{"name":"山药","standard_name":"薯蓣","latinName":"Dioscorea polystachya","synonyms":["淮山","玉延"],"family":"薯蓣科薯蓣属","origin":"东亚"}','{"category":"中药材/蔬果/蒸菜","growthHabit":"多年生缠绕草藤本","flowerColor":"淡黄白色","floweringSeason":"夏季","fragrance":"淡香","landscapeUse":"垂直绿化、深植袋栽培、药食同源园","potSuitable":true,"symbolism":"延年益寿"}','{"careDifficulty":"中等","lightRequirement":"喜光照充足","waterRequirement":"中等，忌积水（易烂根）","temperature":"15-28℃","humidity":"适应环境","soilRequirement":"土层深厚、疏松肥沃的沙质壤土","droughtTolerance":"较强","shadeTolerance":"一般","coldTolerance":"较强（地下块茎可越冬）","watering":"见干见湿，保持根部通气","fertilizing":"喜有机肥及钾肥","pruning":"引导藤蔓向上攀爬","propagation":"块茎切段（芦头）、零余子","pests":"炭疽病、线虫","safetyInfo":"生山药粘液含皂苷，皮肤接触可能发痒","specialNotes":"带皮蒸食营养最佳，是传统蒸菜的经典配餐"}','2026-01-24 09:16:31',NULL);
INSERT INTO "plants" VALUES('TongHao','茼蒿','蔬菜类/蒸菜','容易','{"name":"茼蒿","standard_name":"茼蒿","latinName":"Glebionis coronaria","synonyms":["皇帝菜","蓬蒿"],"family":"菊科茼蒿属","origin":"地中海沿岸"}','{"category":"蔬菜类/蒸菜","growthHabit":"一二年生草本","flowerColor":"黄色或白色","floweringSeason":"春季","fragrance":"独特清香","landscapeUse":"阳台菜园、冬春季绿叶景观","potSuitable":true,"symbolism":"富贵、长寿"}','{"careDifficulty":"容易","lightRequirement":"喜光照，耐半阴","waterRequirement":"喜湿润，不耐干旱","temperature":"15-22℃","humidity":"中高湿度","soilRequirement":"疏松肥沃、保水力强的营养土","droughtTolerance":"差","shadeTolerance":"较强","coldTolerance":"强（可耐短暂霜冻）","watering":"保持盆土湿润，避免由于干旱导致纤维变粗","fertilizing":"生长期追施速效氮肥","pruning":"多次采摘幼苗和嫩茎","propagation":"播种","pests":"蚜虫","safetyInfo":"无毒","specialNotes":"著名的''粉蒸茼蒿''素材，蒸后清香柔嫩"}','2026-01-24 09:16:32',NULL);
INSERT INTO "plants" VALUES('QieZi','茄子','蔬菜类/蒸菜','容易','{"name":"茄子","standard_name":"茄","latinName":"Solanum melongena","synonyms":["矮瓜","紫茄"],"family":"茄科茄属","origin":"亚洲热带地区"}','{"category":"蔬菜类/蒸菜","growthHabit":"一年生草本","flowerColor":"紫色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"阳台盆栽菜园、夏季观果植株","potSuitable":true,"symbolism":"长寿、幸福"}','{"careDifficulty":"容易","lightRequirement":"喜充足日照","waterRequirement":"水量需求高，但不耐积水","temperature":"20-30℃","humidity":"中等湿度","soilRequirement":"肥沃、深厚、排水良好的沙壤土","droughtTolerance":"差","shadeTolerance":"低","coldTolerance":"极弱（惧霜冻）","watering":"早晚观察，果实膨大期不能缺水","fertilizing":"重肥植物，定植底肥配后续追肥","pruning":"适时摘除下部老叶和不结果的小分枝","propagation":"播种","pests":"红蜘蛛、二十八星瓢虫","safetyInfo":"无毒","specialNotes":"蒸茄子拌蒜泥是深受大众喜爱的健康开胃菜"}','2026-01-24 09:16:32',NULL);
INSERT INTO "plants" VALUES('HuLuoBo','胡萝卜','普通蔬菜','中等','{"name":"胡萝卜","standard_name":"胡萝卜","latinName":"Daucus carota subsp. sativus","synonyms":["金笋","红萝卜"],"family":"伞形科胡萝卜属","origin":"亚洲西南部"}','{"category":"普通蔬菜","growthHabit":"二年生草本（常作一年生栽培）","flowerColor":"白色","floweringSeason":"夏季（非食用期）","fragrance":"叶片带胡萝卜香气","landscapeUse":"盆栽观叶（叶片如蕨类）、深桶种植趣味景观","potSuitable":true,"symbolism":"健康、多产"}','{"careDifficulty":"中等","lightRequirement":"全日照","waterRequirement":"保持土壤稳定湿润，忌忽干忽湿导致裂果","temperature":"15-25℃","humidity":"中等环境","soilRequirement":"极其疏松深厚的沙质土（无石块干扰）","droughtTolerance":"一般","shadeTolerance":"低","coldTolerance":"强（地下肉质根极其耐寒）","watering":"幼苗期需精细供水，后期保持湿润","fertilizing":"施足底肥，忌由于过量氮肥导致的叶多根小","pruning":"需适时及时的间苗以保证根部生长空间","propagation":"播种","pests":"胡萝卜微茎蛾、蚜虫","safetyInfo":"无毒","specialNotes":"阳台盆栽建议选择短根品种，且蒸熟后更有利于由于吸收吸收胡萝卜素"}','2026-01-24 09:16:33',NULL);
INSERT INTO "plants" VALUES('LaJiao','辣椒','普通蔬菜','容易','{"name":"辣椒","standard_name":"辣椒","latinName":"Capsicum annuum","synonyms":["海椒","辣子"],"family":"茄科辣椒属","origin":"墨西哥热带地区"}','{"category":"普通蔬菜","growthHabit":"一年生或多年生草本/灌木","flowerColor":"白色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"观果型阳台植物、色彩缤纷菜园","potSuitable":true,"symbolism":"红红火火、热情澎湃"}','{"careDifficulty":"容易","lightRequirement":"全日照环境","waterRequirement":"水量需求中等，保持盆土微干再浇透","temperature":"20-30℃","humidity":"中等偏干燥环境","soilRequirement":"肥沃排水良好的钙质土","droughtTolerance":"中等","shadeTolerance":"低","coldTolerance":"极弱","watering":"见干见湿，特别是结果期供水要足","fertilizing":"生长期重施磷钾肥","pruning":"需通过分枝打顶增加结果量","propagation":"播种","pests":"蚜虫、白粉虱、炭疽病","safetyInfo":"辛辣成分易刺激皮肤及眼睛，触摸后需洗手","specialNotes":"色彩丰富的朝天椒是阳台观赏性的巅峰蔬菜蔬菜"}','2026-01-24 09:16:34',NULL);
INSERT INTO "plants" VALUES('YuMianDuo','榆黄蘑','食用菌/蒸菜','一般','{"name":"榆黄蘑","standard_name":"榆黄蘑","latinName":"Pleurotus citrinopileatus","synonyms":["金顶侧耳","玉皇菇"],"family":"侧耳科侧耳属","origin":"东亚、中国北方"}','{"category":"食用菌/蒸菜","growthHabit":"木腐菌（丛生）","flowerColor":"金黄色","floweringSeason":"春秋两季萌发","fragrance":"由于浓郁菌菇鲜香","landscapeUse":"室内趣味栽培（菌棒）、阳台遮荫死角特色生产","potSuitable":true,"symbolism":"富贵、招财"}','{"careDifficulty":"一般","lightRequirement":"喜阴凉散射光，禁止直射光线","waterRequirement":"水量需求极高且需维持环境极端湿润","temperature":"20-26℃","humidity":"极浓度高空间湿度（＞85%）","soilRequirement":"特制的由于由于木屑或棉籽壳的培养基","droughtTolerance":"无（干旱直接导致死亡）","shadeTolerance":"极强（必须阴暗）","coldTolerance":"较强（菌丝体可耐零下低温休眠）","watering":"由于严禁直接向幼芽喷大水，应向周围空间喷雾增湿","fertilizing":"培养基已含足够养分，不需额外液肥","pruning":"成熟后一丛全采，清理剩余基座","propagation":"孢子、菌丝转接（家庭通常使用成品菌棒）","pests":"菇蚊、由于过湿环境导致的绿霉病","safetyInfo":"美味食用菌，绝大多数人群极其安全安全性高","specialNotes":"金黄色的色彩极佳，蒸制食用鲜美无比"}','2026-01-24 09:16:34',NULL);
