INSERT INTO "plants" VALUES('XiHongShi','西红柿','果菜类','中等','{"name":"西红柿","standard_name":"番茄","latinName":"Solanum lycopersicum","synonyms":["番茄"],"family":"茄科番茄属","origin":"南美洲"}','{"category":"果菜类","growthHabit":"直立或蔓生","flowerColor":"黄色","floweringSeason":"春夏季","fragrance":"无明显香味","landscapeUse":"食用、阳台种植","potSuitable":true,"symbolism":"丰收、活力"}','{"careDifficulty":"中等","lightRequirement":"充足日照","waterRequirement":"中等","temperature":"18–28℃","humidity":"普通","soilRequirement":"肥沃排水良好","droughtTolerance":"较弱","shadeTolerance":"较弱","coldTolerance":"较弱","watering":"避免忽干忽湿","fertilizing":"结果期补钾","pruning":"打侧芽","propagation":"播种","pests":"白粉虱","safetyInfo":"可食用","specialNotes":"需支架"}','2026-01-24 09:46:47',NULL);
INSERT INTO "plants" VALUES('HuangHua','黄瓜','果菜类','容易','{"name":"黄瓜","standard_name":"黄瓜","latinName":"Cucumis sativus","synonyms":[],"family":"葫芦科黄瓜属","origin":"印度"}','{"category":"果菜类","growthHabit":"蔓生","flowerColor":"黄色","floweringSeason":"夏季","fragrance":"无","landscapeUse":"食用、藤本遮阴","potSuitable":true,"symbolism":"清爽"}','{"careDifficulty":"容易","lightRequirement":"充足日照","waterRequirement":"偏高","temperature":"20–30℃","humidity":"喜湿","soilRequirement":"疏松肥沃","droughtTolerance":"较弱","shadeTolerance":"较弱","coldTolerance":"较弱","watering":"勤浇水","fertilizing":"勤施薄肥","pruning":"摘心促侧蔓","propagation":"播种","pests":"蚜虫","safetyInfo":"可食用","specialNotes":"需搭架"}','2026-01-24 09:46:47',NULL);
INSERT INTO "plants" VALUES('ShengJiang','生姜','多年生草本（作一年生栽培）','中等','{"name":"生姜","standard_name":"姜","latinName":"Zingiber officinale","synonyms":["鲜姜","姜根"],"family":"姜科姜属","origin":"东南亚"}','{"category":"多年生草本（作一年生栽培）","growthHabit":"直立丛生，地下根茎膨大","flowerColor":"黄绿色","floweringSeason":"夏季","fragrance":"具有辛辣清香气味","landscapeUse":"食用作物、家庭菜园","potSuitable":true,"symbolism":"温暖、生命力、驱寒"}','{"careDifficulty":"中等","lightRequirement":"半阴或散射光","waterRequirement":"中等偏高","temperature":"18–30℃","humidity":"喜较高空气湿度","soilRequirement":"疏松、肥沃、排水良好的壤土","droughtTolerance":"较弱","shadeTolerance":"较强","coldTolerance":"弱","watering":"保持土壤湿润但不积水","fertilizing":"生长期追施有机肥或复合肥","pruning":"一般不需修剪，枯叶可清除","propagation":"根茎分块繁殖","pests":"姜螟、根腐病","safetyInfo":"可食用","specialNotes":"忌低温和积水，适合温暖季节种植"}','2026-01-24 10:23:52',NULL);
INSERT INTO "plants" VALUES('Suan','蒜','一年生或二年生草本','容易','{"name":"蒜","standard_name":"大蒜","latinName":"Allium sativum","synonyms":["蒜头","蒜瓣"],"family":"石蒜科葱属","origin":"中亚地区"}','{"category":"一年生或二年生草本","growthHabit":"直立生长，地下鳞茎分瓣","flowerColor":"白色或淡紫色","floweringSeason":"夏季","fragrance":"具有强烈蒜香味","landscapeUse":"调味作物、家庭菜园","potSuitable":true,"symbolism":"驱邪、健康"}','{"careDifficulty":"容易","lightRequirement":"充足日照","waterRequirement":"中等","temperature":"12–25℃","humidity":"普通","soilRequirement":"疏松、排水良好的壤土","droughtTolerance":"中等","shadeTolerance":"较弱","coldTolerance":"较强","watering":"生长期保持湿润，膨大期控水","fertilizing":"生长期补充磷钾肥","pruning":"抽薹后可摘薹","propagation":"蒜瓣繁殖","pests":"蒜蛆、根腐病","safetyInfo":"可食用","specialNotes":"忌连作，适合秋播"}','2026-01-24 10:24:35',NULL);
INSERT INTO "plants" VALUES('Cong','葱','多年生草本（作一年生栽培）','容易','{"name":"葱","standard_name":"葱","latinName":"Allium fistulosum","synonyms":["大葱","香葱","青葱"],"family":"石蒜科葱属","origin":"中国及中亚地区"}','{"category":"多年生草本（作一年生栽培）","growthHabit":"直立丛生，中空叶片","flowerColor":"白色","floweringSeason":"夏季","fragrance":"具有辛香气味","landscapeUse":"调味蔬菜、家庭菜园","potSuitable":true,"symbolism":"生机、家常"}','{"careDifficulty":"容易","lightRequirement":"充足日照","waterRequirement":"中等","temperature":"15–25℃","humidity":"普通","soilRequirement":"疏松、肥沃、排水良好的壤土","droughtTolerance":"中等","shadeTolerance":"较弱","coldTolerance":"较强","watering":"见干见湿，避免积水","fertilizing":"生长期少量多次追肥","pruning":"随需采收叶片","propagation":"播种或分株","pests":"葱蓟马、潜叶蝇","safetyInfo":"可食用","specialNotes":"耐寒性强，适合多季节种植"}','2026-01-24 10:24:57',NULL);
